async (params, browser) => {
  // Open Instagram post
  await browser.open(`${params.post_url}`)

  // Wait for post to load
  await browser.waitForSelector('article, article[role=\'presentation\'], main[role=\'main\'] div[role=\'presentation\']', 15000)

  // Let post fully render
  await browser.wait(2000)

  // Like the post
  const result = await browser.evaluate(`const unlikeSvg = document.querySelector('svg[aria-label="Unlike"]'); if (unlikeSvg) { return { success: true, message: 'Post is already liked', already_liked: true }; } const likeSvg = document.querySelector('svg[aria-label="Like"]'); if (likeSvg) { const likeBtn = likeSvg.closest('button') || likeSvg.closest('div[role="button"]') || likeSvg.parentElement; if (likeBtn) { likeBtn.click(); await new Promise(r => setTimeout(r, 1000)); const confirmUnlike = document.querySelector('svg[aria-label="Unlike"]'); return { success: !!confirmUnlike, message: confirmUnlike ? 'Post liked successfully' : 'Like button clicked but could not confirm', post_url: params.post_url }; } } return { success: false, message: 'Like button not found. Make sure you are logged in and the post URL is valid.' }`)

  // Wait for like to register
  await browser.wait(1000)

  return result
}
